const AWS = require('aws-sdk');
const dynamodb = new AWS.DynamoDB.DocumentClient();
const sqs = new AWS.SQS();

exports.handler = async (event) => {
    for (const record of event.Records) {
        try {
            const order = JSON.parse(record.body);
            
            // Process payment
            const paymentResult = await processPayment(order);
            
            // Update DynamoDB
            await updateOrderStatus(order.orderId, paymentResult.status, paymentResult.transactionId);
            
        } catch (error) {
            console.error('Error processing order:', error);
            // Continue processing other orders
        }
    }
    return { statusCode: 200 };
};

async function processPayment(order) {
    // Simulate external API call
    const paymentResponse = await fetch('https://api.paymentprocessor.com/charge', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${process.env.PAYMENT_API_KEY}`
        },
        body: JSON.stringify({
            amount: order.amount,
            currency: order.currency,
            card: order.card
        })
    });
    
    const result = await paymentResponse.json();
    
    return {
        status: result.status,
        transactionId: result.transactionId
    };
}

async function updateOrderStatus(orderId, status, transactionId) {
    const params = {
        TableName: process.env.ORDERS_TABLE,
        Key: { orderId },
        UpdateExpression: 'SET #status = :status, #transactionId = :transactionId, #updatedAt = :updatedAt',
        ExpressionAttributeNames: {
            '#status': 'status',
            '#transactionId': 'transactionId',
            '#updatedAt': 'updatedAt'
        },
        ExpressionAttributeValues: {
            ':status': status,
            ':transactionId': transactionId,
            ':updatedAt': new Date().toISOString()
        }
    };
    
    await dynamodb.update(params).promise();
}